import { Link } from "react-router-dom";
import { epochTogmt } from "../../utils/Common";
import authService from "src/auth/auth.service";
import { cilInfo } from "@coreui/icons";
import CIcon from "@coreui/icons-react";
import StatusDetails from "src/utils/StatusDetails";
import StatusDrop from "src/utils/StatusDrop";
import { v4 as uuidv4 } from 'uuid';

export const tableUserViewQueryConstant = (fetchUserViewQueryList, handleConfirmModal) => {
    return [
        {
            id: 1,
            name: "First Name",
            cell: (row) => {
                return (
                    <>
                        <Link to={`/user-view-query/details/${row?._id}`}>
                            <span className="sub">{row.firstName}</span>
                        </Link>
                        {authService.getPermission("REMARKS_TAB") &&
                            <Link to={{pathname: "/user-view-query/remarks"}} state={{ "businessQueryId": row?._id, type: "PAGE_QUERY", "businessQueryStatus": row.status}} style={{marginLeft: "8px"}}>
                                <CIcon icon={cilInfo} customClassName="nav-icon" width={20} />
                            </Link>
                        }
                    </>

                );
            },
            sortable: true,
            reorder: true,
            grow: 2,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 2,
            name: "Last Name",
            selector: (row) => row.lastName,
        },
        {
            id: 3,
            name: "Location",
            grow: 3,
            cell: (row) => {
                return (
                    <a href={row?.pageUrl} target="_blank">
                        <span className="sub">{row.pageUrl}</span>
                    </a>
                );
            },
        },
        {
            id: 3,
            name: "Email",
            selector: (row) => row.email
        },
        {
            id: 4,
            name: "Country Code",
            selector: (row) => "+"+row.countryISDCode
        },
        {
            id: 5,
            name: "Phone No.",
            selector: (row) => row.phoneNumber
        },
        {
            id: 6,
            name: "Company",
            selector: (row) => row.companyName || "-"
        },
        {
            id: 7,
            name: "Action",
            cell: (row) => {
                return (
                    <StatusDrop
                        id={row._id}
                        status={row.status}
                        type={'PAGE_QUERY'}
                        action={fetchUserViewQueryList}
                        key={uuidv4()}
                        publishPermission={"USER_VIEW_QUERY_STATUS_UPDATE"}
                    />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 8,
            name: "Status",
            cell: (row) => {
                return (
                    <StatusDetails status={row.status} key={uuidv4()} />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 9,
            name: "Website",
            selector: (row) => row.website || "-"
        },
        {
            id: 10,
            name: "Date",
            selector: (row) => epochTogmt(row.createTime)
        },
        {
            id: 11,
            name: "Closed By",
            selector: (row) => row.closedBy ? row.closedBy : "-"
        },
        {
            id: 12,
            name: "Delete",
            cell: (row) => {
                return <i className={"fa-regular fa-trash-can" + (row.status === "ENABLE" || !authService.getPermission("DELETE") ? " disable" : "")} onClick={(e) => { handleConfirmModal(row._id) }}></i>;
            },
            sortable: true,
            reorder: true,
        },
    ];
};
